import React, { useState } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton,
  LinearProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TipsAndUpdatesIcon from '@mui/icons-material/TipsAndUpdates';
import VerifiedIcon from '@mui/icons-material/Verified';

import BarChartIcon from '@mui/icons-material/BarChart';



// Testimonial quality scores
const originalScores = {
  emotional: 32,
  specificity: 25,
  credibility: 40,
  overall: 34
};

const enhancedScores = {
  emotional: 88,
  specificity: 92,
  credibility: 85,
  overall: 89
};

// Helper function to get color based on score
const getScoreColor = (score) => {
  if (score >= 80) return 'success.main';
  if (score >= 60) return 'warning.main';
  return 'error.main';
};

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});
  const [originalScores, setOriginalScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [enhancedScores, setEnhancedScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [spotlightActive, setSpotlightActive] = useState(false);

  const steps = [
    'Enter original testimonial',
    'Get AI enhancement',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
    setOriginalScores({ emotional: 0, specificity: 0, credibility: 0 });
    setEnhancedScores({ emotional: 0, specificity: 0, credibility: 0 });
    setSpotlightActive(false);
  };

  const getScoreColor = (score) => {
    if (score < 50) return 'error.main';
    if (score < 75) return 'warning.main';
    return 'success.main';
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 6, md: 8 },
          pb: { xs: 8, md: 10 },
          position: 'relative',
          minHeight: '80vh',
          display: 'flex',
          alignItems: 'center'
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg" sx={{ position: 'relative' }}>
          <Box sx={{ display: 'flex', flexDirection: { xs: 'column', md: 'row' }, alignItems: 'center' }}>
            {/* Left side - Hero text */}
            <Box sx={{ width: { xs: '100%', md: '50%' }, pr: { md: 6 }, mb: { xs: 6, md: 0 } }}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography 
                variant="h2" 
                component="h1" 
                gutterBottom
                sx={{ 
                  fontWeight: 700,
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  lineHeight: 1.2
                }}
              >
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  sx={{ px: 3, py: 1.5 }}
                  endIcon={<ArrowForwardIcon />}
                >
                  Enhance a Testimonial
                </Button>

                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                  onClick={handleReset}
                >
                  Try Demo
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1.5 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" color="text.secondary">
                  <Box component="span" sx={{ fontWeight: 600, color: 'text.primary' }}>4.9/5</Box> from 200+ users
                </Typography>
              </Box>
            </Box>

            {/* Right side - Interactive Demo */}
            <Box 
              sx={{ 
                width: { xs: '100%', md: '50%' },
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'flex-start',
                mt: { xs: 2, md: 0 }
              }}
            >
              <Card 
                elevation={3}
                sx={{ 
                  width: '100%', 
                  maxWidth: 450,
                  borderRadius: 3,
                  overflow: 'visible',
                  bgcolor: '#FCFCFF'
                }}
              >
                <CardContent sx={{ p: 0 }}>
                  {/* Demo Header */}
                  <Box sx={{ 
                    p: 2, 
                    borderBottom: '1px solid rgba(0, 0, 0, 0.08)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between'
                  }}>
                    <Typography variant="h6" sx={{ fontWeight: 600 }}>
                      Try It Yourself
                    </Typography>
                    <Button 
                      size="small" 
                      onClick={handleReset}
                      startIcon={<PlayArrowIcon />}
                    >
                      Restart
                    </Button>
                  </Box>

                  {/* Stepper */}
                  <Stepper 
                    activeStep={activeStep} 
                    sx={{ 
                      px: 3, 
                      py: 2,
                      '& .MuiStepConnector-line': {
                        borderColor: theme.palette.primary.light
                      }
                    }}
                    alternativeLabel
                  >
                    {steps.map((label, index) => (
                      <Step key={label} completed={completed[index]}>
                        <StepButton onClick={handleStep(index)}>
                          <StepLabel StepIconProps={{
                            sx: {
                              '&.Mui-active': {
                                color: theme.palette.primary.main
                              },
                              '&.Mui-completed': {
                                color: '#4CAF50'
                              }
                            }
                          }}>
                            {label}
                          </StepLabel>
                        </StepButton>
                      </Step>
                    ))}
                  </Stepper>

                  {/* Step Content */}
                  <Box sx={{ p: 3, minHeight: 300 }}>
                    {activeStep === 0 && (
                      <Fade in={activeStep === 0}>
                        <Box>
                          <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                            Original Client Testimonial
                          </Typography>
                          <TextField
                            fullWidth
                            multiline
                            rows={4}
                            variant="outlined"
                            value={originalText}
                            placeholder="Enter your client's original testimonial here..."
                            sx={{ mb: 3 }}
                          />
                          <Button
                            variant="contained"
                            color="primary"
                            endIcon={<AutoAwesomeIcon />}
                            onClick={handleNext}
                            fullWidth
                            sx={{ py: 1.5 }}
                          >
                            Enhance Testimonial
                          </Button>
                        </Box>
                      </Fade>
                    )}

                    {activeStep === 1 && (
                      <Fade in={activeStep === 1}>
                        <Box>
                          <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                            <AutoAwesomeIcon sx={{ color: theme.palette.primary.main, mr: 1 }} />
                            <Typography variant="subtitle2" color="primary.main">
                              AI-Enhanced Testimonial
                            </Typography>
                          </Box>

                          <Paper 
                            elevation={0} 
                            sx={{ 
                              p: 2, 
                              mb: 3, 
                              bgcolor: 'rgba(93, 95, 239, 0.05)',
                              border: '1px solid rgba(93, 95, 239, 0.2)',
                              borderRadius: 2
                            }}
                          >
                            <Typography variant="body1">
                              {enhancedText}
                            </Typography>
                          </Paper>

                          <Box sx={{ display: 'flex', gap: 2 }}>
                            <Button
                              variant="outlined"
                              color="primary"
                              startIcon={<EditIcon />}
                              onClick={handleStep(0)}
                              sx={{ flexGrow: 1 }}
                            >
                              Edit
                            </Button>
                            <Button
                              variant="contained"
                              color="primary"
                              endIcon={<SendIcon />}
                              onClick={handleNext}
                              sx={{ flexGrow: 2 }}
                            >
                              Send for Approval
                            </Button>
                          </Box>
                        </Box>
                      </Fade>
                    )}

                    {activeStep === 2 && (
                      <Fade in={activeStep === 2}>
                        <Box>
                          <Box 
                            sx={{ 
                              p: 3, 
                              mb: 3, 
                              bgcolor: 'rgba(76, 175, 80, 0.05)',
                              border: '1px solid rgba(76, 175, 80, 0.2)',
                              borderRadius: 2,
                              textAlign: 'center'
                            }}
                          >
                            <CheckCircleIcon sx={{ fontSize: 48, color: '#4CAF50', mb: 1 }} />
                            <Typography variant="h6" gutterBottom>
                              Testimonial Approved!
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                              Your client has verified this testimonial and it's ready to use.
                            </Typography>
                          </Box>

                          <Box sx={{ display: 'flex', gap: 2 }}>
                            <Button
                              variant="outlined"
                              color="primary"
                              onClick={handleReset}
                              sx={{ flexGrow: 1 }}
                            >
                              Try Again
                            </Button>
                            <Button
                              variant="contained"
                              color="primary"
                              component={RouterLink}
                              to="/enhance"
                              sx={{ flexGrow: 2 }}
                            >
                              Create Your Own
                            </Button>
                          </Box>
                        </Box>
                      </Fade>
                    )}
                  </Box>
                </CardContent>
              </Card>
            </Box>
          </Box>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: '#F8F9FF' }}>
        <Container maxWidth="lg">
          <Typography 
            variant="h3" 
            align="center" 
            gutterBottom
            sx={{ fontWeight: 700 }}
          >
            How It Works
          </Typography>

          <Typography 
            variant="subtitle1" 
            align="center" 
            color="text.secondary"
            sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}
          >
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4}>
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* Authority & Credibility Score Feature Highlight */}
      <Box sx={{ mt: 8, p: 4, bgcolor: 'white', borderRadius: 4, boxShadow: '0 10px 40px rgba(0, 0, 0, 0.1)' }}>
        <Grid container spacing={4} alignItems="center">
          <Grid item xs={12} md={6}>
            <Chip
              icon={<BarChartIcon />}
              label="UNIQUE FEATURE"
              sx={{ 
                mb: 2, 
                bgcolor: 'primary.light', 
                color: 'primary.dark',
                fontWeight: 600,
                '& .MuiChip-icon': { color: 'primary.main' }
              }}
            />
            <Typography variant="h4" gutterBottom fontWeight={700}>
              Authority & Credibility Score
            </Typography>
            <Typography variant="body1" paragraph color="text.secondary">
              Not just a rewrite—get objective metrics on how well your testimonials will convert.
            </Typography>

            <Box sx={{ mb: 3 }}>
              <Stack direction="row" spacing={2} alignItems="center" sx={{ mb: 1 }}>
                <CheckCircleIcon color="success" />
                <Typography variant="subtitle1" fontWeight={600}>
                  Emotional Impact Analysis
                </Typography>
              </Stack>
              <Typography variant="body2" color="text.secondary" sx={{ pl: 4 }}>
                Measures how effectively your testimonial creates an emotional connection with potential clients.
              </Typography>
            </Box>

            <Box sx={{ mb: 3 }}>
              <Stack direction="row" spacing={2} alignItems="center" sx={{ mb: 1 }}>
                <CheckCircleIcon color="success" />
                <Typography variant="subtitle1" fontWeight={600}>
                  Specificity Rating
                </Typography>
              </Stack>
              <Typography variant="body2" color="text.secondary" sx={{ pl: 4 }}>
                Evaluates how detailed and concrete your testimonial is—vague praise doesn't sell, specific results do.
              </Typography>
            </Box>

            <Box sx={{ mb: 3 }}>
              <Stack direction="row" spacing={2} alignItems="center" sx={{ mb: 1 }}>
                <CheckCircleIcon color="success" />
                <Typography variant="subtitle1" fontWeight={600}>
                  Credibility Factor
                </Typography>
              </Stack>
              <Typography variant="body2" color="text.secondary" sx={{ pl: 4 }}>
                Assesses how trustworthy and authentic your testimonial appears to potential clients.
              </Typography>
            </Box>

            <Button 
              variant="contained" 
              color="primary"
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ mt: 2 }}
              endIcon={<ArrowForwardIcon />}
            >
              Try It Now
            </Button>
          </Grid>

          <Grid item xs={12} md={6}>
            <Box sx={{ p: 2, bgcolor: 'grey.50', borderRadius: 4, border: '1px solid rgba(0, 0, 0, 0.08)' }}>
              <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                ORIGINAL TESTIMONIAL
              </Typography>
              <Box sx={{ p: 2, bgcolor: 'white', borderRadius: 2, mb: 3, border: '1px solid rgba(0, 0, 0, 0.08)' }}>
                <Typography variant="body1" sx={{ fontStyle: 'italic' }}>
                  "{originalText}"
                </Typography>
              </Box>

              <Typography variant="subtitle2" gutterBottom sx={{ display: 'flex', alignItems: 'center' }}>
                <WarningAmberIcon sx={{ color: 'error.main', mr: 1, fontSize: 20 }} />
                CREDIBILITY SCORE: LOW
              </Typography>

              <Box sx={{ mb: 3 }}>
                <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
                  <Typography variant="body2" color="text.secondary" sx={{ minWidth: 100 }}>
                    Emotional Impact:
                  </Typography>
                  <LinearProgress 
                    variant="determinate" 
                    value={originalScores.emotional} 
                    sx={{ 
                      flexGrow: 1, 
                      height: 8, 
                      borderRadius: 4,
                      bgcolor: 'grey.200',
                      '& .MuiLinearProgress-bar': {
                        bgcolor: getScoreColor(originalScores.emotional)
